arguments.command:
cat > /tmp/test_stackalloc_nint.cs << 'EOF'
using System;

class Program
{
    static void Main()
    {
        Span<nint> nints = stackalloc nint[4];
        nints[0] = 10;
        nints[1] = 20;
        nints[2] = 30;
        nints[3] = 40;

        Console.WriteLine($"Span<nint> length: {nints.Length}");
        for (int i = 0; i < nints.Length; i++)
            Console.WriteLine($"  nints[{i}] = {nints[i]}");

        Span<nuint> nuints = stackalloc nuint[3];
        nuints[0] = 100;
        nuints[1] = 200;
        nuints[2] = 300;

        Console.WriteLine($"Span<nuint> length: {nuints.Length}");
        for (int i = 0; i < nuints.Length; i++)
            Console.WriteLine($"  nuints[{i}] = {nuints[i]}");

        Console.WriteLine($"sizeof(nint) = {sizeof(nint)}");
    }
}
EOF
cd /tmp && dotnet-script test_stackalloc_nint.cs 2>/dev/null || dotnet run --project . 2>/dev/null || (mkdir -p stackalloc_test && cd stackalloc_test && dotnet new console --force -q && cp /tmp/test_stackalloc_nint.cs Program.cs && dotnet run)

